import fs from 'fs';
import path from 'path';
import matter from 'gray-matter';
import { marked } from 'marked';

const SITE_URL = 'https://dashchat.org';
const SITE_NAME = 'Dash Chat';
const POSTS_DIR = 'blog/posts';
const IMAGES_DIR = 'blog/images';
const OUT_DIR = 'public';
const BLOG_IMAGES_OUT = path.join(OUT_DIR, 'blog-images');

const REQUIRED_FIELDS = ['title', 'date', 'author', 'description'];

// Slugs that would clobber site files generated by Vite or kept in public/.
const RESERVED_SLUGS = new Set(['index', '404', 'blog', 'sitemap', 'rss']);

// A safe slug is lowercase letters, numbers and single hyphens only.
// Prevents path traversal (no slashes/dots) and odd URLs.
function isSafeSlug(slug) {
  return /^[a-z0-9]+(?:-[a-z0-9]+)*$/.test(slug);
}

function readPosts() {
  if (!fs.existsSync(POSTS_DIR)) {
    console.warn(`Warning: ${POSTS_DIR} does not exist. No posts to build.`);
    return [];
  }

  const files = fs.readdirSync(POSTS_DIR).filter(f => f.endsWith('.md'));
  const posts = [];

  for (const file of files) {
    const raw = fs.readFileSync(path.join(POSTS_DIR, file), 'utf-8');
    const { data, content } = matter(raw);
    const slug = file.replace(/\.md$/, '');

    if (!isSafeSlug(slug)) {
      console.warn(`Warning: ${file} has an unsafe slug "${slug}". Use only lowercase letters, numbers, and hyphens. Skipping.`);
      continue;
    }
    if (RESERVED_SLUGS.has(slug)) {
      console.warn(`Warning: ${file} uses reserved slug "${slug}" which would overwrite a site file. Skipping.`);
      continue;
    }

    const missing = REQUIRED_FIELDS.filter(f => !data[f]);
    if (missing.length > 0) {
      console.warn(`Warning: ${file} is missing required fields: ${missing.join(', ')}. Skipping.`);
      continue;
    }

    if (data.date instanceof Date) {
      data.date = data.date.toISOString().split('T')[0];
    }
    if (data.modified instanceof Date) {
      data.modified = data.modified.toISOString().split('T')[0];
    }

    posts.push({ slug, data, content, file });
  }

  posts.sort((a, b) => (b.data.date > a.data.date ? 1 : -1));
  return posts;
}

function escapeHtml(str) {
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

function formatDate(dateStr) {
  const d = new Date(dateStr + 'T00:00:00Z');
  return d.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric', timeZone: 'UTC' });
}

